import React from 'react';

function LogementHeader() {
    return (
        <div className="logement__header">
            <h1>Cozy loft on the Canal Saint-Martin</h1>
            <h2>Paris, Île-de-France</h2>
            <div className="logement__tags">
                <span>Cozy</span>
                <span>Canal</span>
                <span>Paris 10</span>

            </div>
        </div>
    );
}

export default LogementHeader;
